const envelope = $input.first().json ?? {};
const payload = envelope.body && typeof envelope.body === 'object' ? envelope.body : envelope;
const metadata = payload.metadata ?? {};
const rawTags = payload.tags ?? metadata.tags ?? [];
const tags = Array.isArray(rawTags)
  ? rawTags.filter((tag) => tag !== null && tag !== undefined && String(tag).trim()).map((tag) => String(tag).trim())
  : [];
const extractedText = String(payload.extractedText ?? payload.text ?? '').trim();
const ocrText = String(payload.ocrText ?? '').trim();
const rawHint = String(payload.docTypeHint ?? metadata.documentTypeHint ?? '').trim();
const hintMap = {
  NDA: 'nda',
  Employment: 'employment contract',
  Lease: 'lease agreement',
  Service: 'service agreement',
  Sales: 'sales agreement',
  Other: 'legal document',
};
const normalizedHint = hintMap[rawHint] ?? (rawHint ? rawHint.toLowerCase().replace(/_/g, ' ') : 'legal document');
const fileName = String(payload.fileName ?? metadata.documentName ?? 'uploaded-document');
const priority = String(payload.priority ?? metadata.priority ?? 'medium').toLowerCase();
const submittedBy = String(payload.submittedBy ?? metadata.submittedBy ?? 'n8n_demo');
const sourceSystem = String(payload.sourceSystem ?? metadata.sourceSystem ?? 'n8n');
const caseId = String(payload.caseId ?? metadata.caseId ?? `case_${Date.now()}`);
const language = String(payload.language ?? 'vi').toLowerCase();

return [{
  json: {
    caseId,
    language,
    extractedText,
    ocrText,
    textLength: extractedText.length,
    metadata: {
      documentName: fileName,
      documentTypeHint: normalizedHint,
      priority,
      submittedBy,
      sourceSystem,
      tags,
    },
    _startedAt: Date.now(),
  },
}];

const item = $input.first().json;
const extractedText = String(item.extractedText ?? '');
const ocrText = String(item.ocrText ?? '');

if (extractedText.length >= 80) {
  return [{ json: { ...item, ocrFallbackUsed: false, ocrFallbackSource: null } }];
}

if (ocrText.length >= 80) {
  return [{
    json: {
      ...item,
      extractedText: ocrText,
      textLength: ocrText.length,
      ocrFallbackUsed: true,
      ocrFallbackSource: 'payload.ocrText',
    },
  }];
}

return [{
  json: {
    ...item,
    _error: 'LOW_TEXT_CONTENT',
    _errorMessage: `Extracted text too short (${extractedText.length} chars) and no OCR fallback text was provided.`,
    needsAttention: true,
    qualityWarning: true,
    ocrFallbackUsed: false,
    ocrFallbackSource: null,
  },
}];

const item = $input.first().json;
return [{
  json: {
    success: false,
    caseId: item.caseId,
    error: {
      code: item._error ?? 'WORKFLOW_ERROR',
      message: item._errorMessage ?? 'The workflow failed before calling FastAPI.',
    },
    routeDecision: {
      queue: 'ocr_manual_queue',
      reason: 'pre_ai_validation_error',
      autoEscalated: true,
    },
    orchestration: {
      ocrFallbackUsed: Boolean(item.ocrFallbackUsed),
      ocrFallbackSource: item.ocrFallbackSource ?? null,
      textLength: item.textLength ?? 0,
    },
    nextStep: 'Provide OCR text or replace the source file with a text-based document.',
  },
}];

const item = $input.first().json;
return [{
  json: {
    reviewPayload: {
      caseId: item.caseId,
      language: item.language,
      extractedText: item.extractedText,
      metadata: item.metadata,
    },
    reviewMeta: {
      ocrFallbackUsed: Boolean(item.ocrFallbackUsed),
      ocrFallbackSource: item.ocrFallbackSource ?? null,
      textLength: item.textLength ?? 0,
      startedAt: item._startedAt ?? Date.now(),
    },
  },
}];

const item = $input.first().json;
const preservedReviewMeta = $('Build Review Payload').first().json.reviewMeta ?? item.reviewMeta ?? {};
const review = {
  caseId: item.caseId,
  docType: item.docType,
  confidence: item.confidence,
  riskScore: item.riskScore,
  riskLevel: item.riskLevel,
  riskFlags: item.riskFlags ?? [],
  extractedFields: item.extractedFields ?? {},
  recommendedAction: item.recommendedAction,
  summary: item.summary,
  needsAttention: Boolean(item.needsAttention),
  qualityWarning: Boolean(item.qualityWarning),
  disclaimer: item.disclaimer ?? null,
  meta: item.meta ?? {},
};

let queue = 'normal_review_queue';
let reason = 'default';
if (review.qualityWarning || preservedReviewMeta.ocrFallbackUsed) {
  queue = 'ocr_quality_queue';
  reason = 'quality_warning_or_ocr_fallback';
}
if (review.confidence < 0.55) {
  queue = 'manual_quality_queue';
  reason = 'low_confidence';
}
if (review.riskScore >= 70 || review.needsAttention) {
  queue = 'manual_legal_review_queue';
  reason = 'high_risk_or_needs_attention';
}

const riskLevel = String(review.riskLevel ?? 'medium').toLowerCase();
const notificationTemplate = review.riskScore >= 70
  ? 'legal_review_high_risk'
  : review.needsAttention
    ? 'legal_review_attention'
    : 'legal_review_completed';
const notificationPriority = review.riskScore >= 70 ? 'high' : review.riskScore >= 40 ? 'medium' : 'low';

return [{
  json: {
    success: true,
    routeDecision: {
      queue,
      reason,
      autoEscalated: queue !== 'normal_review_queue',
    },
    review,
    orchestration: {
      ocrFallbackUsed: Boolean(preservedReviewMeta.ocrFallbackUsed),
      ocrFallbackSource: preservedReviewMeta.ocrFallbackSource ?? null,
      textLength: preservedReviewMeta.textLength ?? null,
      fastApiBaseUrl: 'http://172.17.0.1:8080',
    },
    timelineEvent: {
      caseId: review.caseId,
      eventType: 'AI_REVIEW_COMPLETED',
      status: 'AIReviewed',
      riskScore: review.riskScore,
      riskLevel,
      needsAttention: review.needsAttention,
      requestId: review.meta.requestId ?? null,
      source: 'n8n',
    },
    notification: {
      caseId: review.caseId,
      channel: 'internal',
      template: notificationTemplate,
      priority: notificationPriority,
      context: {
        riskScore: review.riskScore,
        riskLevel,
        summary: review.summary,
      },
    },
    nextStep: queue,
  },
}];
